import json

import yaml

from prompty.model import CompactionCompletePayload


def test_load_json_compactioncompletepayload():
    json_data = r"""
    {
      "removed": 5,
      "remaining": 3,
      "summaryLength": 1200
    }
    """
    data = json.loads(json_data, strict=False)
    instance = CompactionCompletePayload.load(data)
    assert instance is not None
    assert instance.removed == 5
    assert instance.remaining == 3
    assert instance.summary_length == 1200


def test_load_yaml_compactioncompletepayload():
    yaml_data = r"""
    removed: 5
    remaining: 3
    summaryLength: 1200

    """
    data = yaml.load(yaml_data, Loader=yaml.FullLoader)
